class Graph {
  constructor() { this.adj=new Map(); }
  addEdge(s,d) {
    if(!this.adj.has(s)) this.adj.set(s,new Set());
    this.adj.get(s).add(d);
  }
  removeEdge(s,d) { this.adj.get(s)?.delete(d); }
  hasPath(s,d) {
    const visited=new Set(), queue=[s];
    while(queue.length) {
      const n=queue.shift();
      if(n===d) return true;
      if(visited.has(n)) continue;
      visited.add(n);
      for(const nb of this.adj.get(n)||[]) queue.push(nb);
    }
    return false;
  }
}
